const rows = $input.all();
const newRows = rows.filter(row => row.json.status === 'New');
if (newRows.length === 0) {
  return [];
}

// Count processed today
const today = new Date().toISOString().split('T')[0];
const processedToday = rows.filter(row => {
  const dateAdded = row.json.date_added || '';
  const status = row.json.status || '';
  return dateAdded.startsWith(today) && status !== 'New';
}).length;

const dailyLimit = parseInt($env.OUTREACH_DAILY_LIMIT || '50');

return [{
  json: {
    newRows: newRows.map(r => r.json),
    processedToday,
    dailyLimit,
    limitReached: processedToday >= dailyLimit
  }
}];

const data = $input.first().json;
const newRows = data.newRows || [];
const daily = data.dailyLimit || 50;
const processed = data.processedToday || 0;
const remaining = daily - processed;

if (remaining <= 0 || newRows.length === 0) {
  return [];
}

// Process ONE lead per run to ensure clean data flow
const row = newRows[0];
return [{
  json: {
    ...row,
    _rowIndex: 0
  }
}];

const hunterResponse = $input.first().json;
const leadData = $('Prepare Rows to Process').first().json;

let email = '';
let firstName = leadData.first_name || '';

if (hunterResponse.data && hunterResponse.data.emails && hunterResponse.data.emails.length > 0) {
  const firstEmail = hunterResponse.data.emails[0];
  email = firstEmail.value || '';
  if (!firstName && firstEmail.first_name) {
    firstName = firstEmail.first_name;
  }
}

// Check Hunter usage warning
const meta = hunterResponse.meta || {};
const usedRequests = meta.calls_per_month || 0;

return [{
  json: {
    ...leadData,
    first_name: firstName,
    email: email,
    _hunterEmail: email,
    _hunterUsage: usedRequests,
    _needsSnov: !email
  }
}];

const snovResponse = $input.first().json;
const leadData = $('Email Found?').first().json;

let email = '';
let firstName = leadData.first_name || '';

if (snovResponse.emails && snovResponse.emails.length > 0) {
  email = snovResponse.emails[0].email || '';
  if (!firstName && snovResponse.emails[0].firstName) {
    firstName = snovResponse.emails[0].firstName;
  }
}

return [{
  json: {
    ...leadData,
    first_name: firstName,
    email: email,
    _snovEmail: email,
    _emailFound: !!email
  }
}];

// Merge items from both Hunter success and Snov.io success paths
const item = $input.first().json;

// Get email from whichever path found it
const email = item.email || item._hunterEmail || item._snovEmail || '';

return [{
  json: {
    ...item,
    email: email
  }
}];

const leadData = $('Merge Email Paths').first().json;
let websiteSnippet = '';

try {
  const body = $input.first().json?.body || $input.first().json?.data || '';
  const text = typeof body === 'string' ? body : JSON.stringify(body);
  // Strip HTML tags
  const stripped = text.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
  websiteSnippet = stripped.substring(0, 200);
} catch (e) {
  websiteSnippet = '';
}

return [{
  json: {
    ...leadData,
    _websiteSnippet: websiteSnippet || leadData.company
  }
}];

