const claudeResponse = $input.first().json;
const leadData = $('Extract Website Text').first().json;

let icebreaker = '';
try {
  icebreaker = claudeResponse.content[0].text.trim();
} catch (e) {
  icebreaker = `I noticed ${leadData.company}'s work in the performance marketing space`;
}

return [{
  json: {
    ...leadData,
    icebreaker
  }
}];

const allRows = $input.all();
const leadData = $('Parse Icebreaker').first().json;
const email = leadData.email || '';

if (!email) {
  return [{ json: { ...leadData, _isDuplicate: false } }];
}

// Check for duplicate email
const isDuplicate = allRows.some(row => {
  const rowEmail = (row.json.email || '').toLowerCase().trim();
  const targetEmail = email.toLowerCase().trim();
  return rowEmail === targetEmail && row.json.status !== 'New';
});

return [{ json: { ...leadData, _isDuplicate: isDuplicate } }];

